#nullable enable // autogenerated

using MVZ2.UI;
using UnityEngine;

namespace MVZ2.Grids
{
    public class GridHPBarView : MonoBehaviour
    {
        public void SetCamera(Camera camera)
        {
            canvas.worldCamera = camera;
        }
        public void SetBarCount(int count)
        {
            barList.updateList(count);
        }
        public int GetBarCount()
        {
            return barList.Count;
        }
        public void UpdateBar(int index, HPBarViewData viewData)
        {
            var bar = barList.getElement<HPBar>(index);
            if (bar.Exists())
            {
                bar.UpdateBar(viewData);
            }
        }
        [SerializeField]
        private Canvas canvas = null!;
        [SerializeField]
        private ElementList barList = null!;
    }
}
